INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('disabled-6f0ba476-moex-00441', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-111-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', 'X1年1月1日甲公司購買一項設備，購買價格$1,000,000，該設備之耐用 年限10年，殘值$100,000。該設備之取得獲得政府補助，並由政府直接撥 款給廠商$300,000。設備之後續衡量採成本模式並以直線法提列折舊，甲 公司按法律規定須於耐用年限屆滿對該設備負有除役之法定義務，於 X1 年1月1日估計應認列該設備之除役負債準備$100,000（折現率10%）。 X3 年 12 月 31 日，甲公司預期耐用年限屆滿時除役支出將下降，且折現 率降低為 8%，估計除役負債準備應為$98,100。試問該設備對甲公司 X4 年度稅前淨利之影響數為：', '["減少$102,848", "減少$95,000", "減少$84,348", "減少$72,848"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:30+00:00", "source_pdf_sha1": "3d8f47c89492", "answer_pdf_sha1": "eb204ac39013", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "304", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00442', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-111-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', '甲公司 X2 年度會計稅前淨利為$520,000，除下列項目外並無其他影響會', '["甲公司 X2 年底資產負債表上產品 保證負債較上一年度減少了$24,000；", "一機器設備 X2 年初帳面金額為 $120,000，課稅基礎為$100,000；X2年底機器設備帳面金額為$90,000，課 稅基礎為$60,000。若各年度稅率均維持20%，則甲公司X2年底認列所得 稅費用之分錄何者正確？", "借記「所得稅費用」$104,000", "借記「遞延所得稅資產」$4,800"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:30+00:00", "source_pdf_sha1": "3d8f47c89492", "answer_pdf_sha1": "eb204ac39013", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "304", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00443', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-111-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', '甲公司於X2年初建造廠房，並向銀行辦理專案借款$8,000,000，專案借款 利率為 10%，銀行於 X2 年 1 月 1 日即撥款$8,000,000 入甲公司之銀行存 款帳戶中。甲公司於X2年1月2日投入工程支出$2,000,000，7月1日再 投入工程支出$6,000,000，未動用之借款資金有存款利息4%，則X2年度 甲公司應資本化之借款成本是多少？', '["$800,000", "$680,000", "$500,000", "$380,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:30+00:00", "source_pdf_sha1": "3d8f47c89492", "answer_pdf_sha1": "eb204ac39013", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "304", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00444', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-111-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', '甲公司於 X2 年因產品誤用不良原料，面臨客戶要求賠償$8,000,000 之訴 訟。X2 年底公司律師評估該訴訟很有可能敗訴，且賠償金額介於 $2,000,000 至$5,000,000 之間。甲公司有投保產品責任險，根據合約規定 ，此一事件幾乎確定可以獲得理賠，且最高可獲得賠償金額$4,000,000。若 公司認列保險理賠是以保險理賠收入科目入帳，則甲公司 X2 年認列之訴 訟損失與保險理賠收入各是多少？', '["$3,500,000、$3,500,000", "$8,000,000、$4,000,000", "$5,000,000、$4,000,000", "$3,500,000、$4,000,000"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:30+00:00", "source_pdf_sha1": "3d8f47c89492", "answer_pdf_sha1": "eb204ac39013", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "304", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00445', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-111-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', '丙公司與A客戶簽訂銷售產品合約，出售甲及乙產品給該客戶，售價分別 為$40,000及$60,000，約定甲產品於X1年8月1日交貨，乙產品於X1年 9月1日交貨，甲產品的貨款須等到A客戶收到乙產品後一個月連同乙產 品貨款一併於10月1 日支付。若丙公司未能準時交付乙產品，則A客戶 不需支付甲產品貨款。丙公司於交付商品時即分別滿足履約義務，則丙公 司X1年8月底及9月底合約資產餘額分別為：', '["$0及$100,000", "$40,000及$100,000", "$0及$0", "$40,000及$0"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:30+00:00", "source_pdf_sha1": "3d8f47c89492", "answer_pdf_sha1": "eb204ac39013", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "304", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00446', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-111-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', '甲公司 X2 年初將一項辦公設備（成本為$760,000，已提列累計折舊 $220,000），以公允價值$480,000 出售予丙公司並立即租回（此交易滿足 IFRS15 移轉控制之規定），租期 4 年，每年初支付租金$82,500，與市場 上性質類似之辦公設備的合理年租金相同。甲公司於租期屆滿時須將該辦 公設備還給丙公司。該辦公設備採直線法折舊，在租期屆滿日甲公司保證 殘值$50,000，甲公司預估須就保證殘值支付丙公司$9,700，丙公司之租賃 隱含利率為8%，且為甲公司所知。試問前述交易對甲公司X2年度稅前淨 利之影響為：（答案四捨五入至元）', '["減少$22,220", "減少$112,304", "減少$124,804", "減少$131,804"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:30+00:00", "source_pdf_sha1": "3d8f47c89492", "answer_pdf_sha1": "eb204ac39013", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "304", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00447', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-111-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', '甲公司X1年12月31日應收帳款總額為$50,000，備抵損失為$3,000。X0 年 12 月 31 日應收帳款總額為$60,000，備抵損失為$4,000。X1 年度之預 期信用減損損失為$7,500，並沖銷無法收回之應收帳款$8,500。若甲公司 X1年度之銷貨收入為$500,000，則自顧客收取之現金數為：', '["$501,500", "$509,000", "$510,000", "$516,500"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:30+00:00", "source_pdf_sha1": "3d8f47c89492", "answer_pdf_sha1": "eb204ac39013", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "304", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00448', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-111-e0b1f2ed', 'sub-disabled-6f0ba476-02', NULL, 'single_choice', '甲公司於X9年5月1日購入一項設備，購買價格$1,000,000，付款條件為 2/30,n/60，並於X9年6月30日完成付款。其他資訊如下：運送成本$15,000 ；運送途中交通違規罰款$5,000；運送途中不慎碰撞之修復費用$40,000； 為安裝設備強化地板支出$30,000；組裝成本$60,000；測試機器設備是否 能正常運轉之成本$20,000；該測試過程所產出樣品之銷售價款$5,000、出 售成本$500、樣品生產成本$2,500；訓練員工使用機器成本$60,000；預計 管理機器將產生之成本$70,000。甲公司所購買設備之成本金額為何？', '["$1,103,000", "$1,105,000", "$1,133,000", "$1,143,000"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:30+00:00", "source_pdf_sha1": "3d8f47c89492", "answer_pdf_sha1": "eb204ac39013", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "304", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00449', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-111-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'essay', '經商失敗的甲，企圖逃債而與好友乙串通，假裝將自己新買的 A 車
賣給乙並完成讓與及過戶登記，並將A車暫交給乙保管。豈料，數日
後乙竟與不知情的丙約定，以自己的名義將該A車以新臺幣（下同）
100 萬元出售給丙；丙先付款20 萬元。然於約定交車日之前，A車遭
第三人丁竊占私用，拒不歸還，以致乙無法如期交車。試問：乙得否向
丁主張所有物返還請求權？丙得否逕行解除該A車買賣契約？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:30+00:00", "source_pdf_sha1": "ea77fa772aee", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "304", "s": "0403", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('disabled-6f0ba476-moex-00450', 'disabled-6f0ba476', 'disabled-6f0ba476-moex-111-9b7ab1bb', 'sub-disabled-6f0ba476-03', NULL, 'essay', '甲男與乙女結婚後，生育一子丙；後因甲與丁女有婚外情，乙女在爭
吵後帶著丙在外租屋，而與甲分居，後甲接其寡母庚同住。於丁女為
甲生下一女戊後，甲支付丁、戊二人全部的生活費用。之後甲車禍過
世，其所留遺產應由何人及依何比例繼承？（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:30+00:00", "source_pdf_sha1": "ea77fa772aee", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "304", "s": "0403", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "民法", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "財稅行政"}'::jsonb, NULL)
